// Parse and enrich error data
const errorData = $input.first().json;

const enrichedError = {
  // Error identification
  error_id: `err_${Date.now()}_${Math.random().toString(36).substr(2, 9)}`,

  // Source information
  source_workflow: errorData.workflow_name || 'unknown',
  source_node: errorData.node_name || 'unknown',
  call_id: errorData.call_id || null,

  // Error details
  error_type: errorData.error_type || 'unknown',
  error_message: errorData.error_message || 'No message provided',
  error_stack: errorData.error_stack || null,
  status_code: errorData.status_code || null,

  // Retry information
  retry_count: errorData.retry_count || 0,
  max_retries: 3,
  retry_eligible: errorData.retry_eligible !== false,

  // Context
  input_data: errorData.input_data || null,

  // Timestamps
  occurred_at: errorData.occurred_at || new Date().toISOString(),
  processed_at: new Date().toISOString(),

  // Severity classification
  severity: classifySeverity(errorData)
};

function classifySeverity(err) {
  // Critical: payment, data loss, security
  if (err.error_message?.includes('payment') || 
      err.error_message?.includes('security') ||
      err.error_message?.includes('auth')) {
    return 'critical';
  }
  // High: processing failures, API errors
  if (err.status_code >= 500 || 
      err.error_type === 'processing_failed') {
    return 'high';
  }
  // Medium: retryable errors
  if (err.status_code >= 400 && err.status_code < 500) {
    return 'medium';
  }
  // Low: everything else
  return 'low';
}

return { json: enrichedError };

// Calculate retry delay with exponential backoff
const errorData = $input.first().json;
const retryCount = errorData.retry_count + 1;

// Exponential backoff: 2^retryCount * 1000ms (2s, 4s, 8s)
const delayMs = Math.pow(2, retryCount) * 1000;

// Prepare retry payload
const retryPayload = {
  ...errorData.input_data,
  _retry_metadata: {
    retry_count: retryCount,
    original_error_id: errorData.error_id,
    retry_at: new Date(Date.now() + delayMs).toISOString()
  }
};

// Wait for backoff delay
await new Promise(resolve => setTimeout(resolve, delayMs));

return { 
  json: {
    retry_payload: retryPayload,
    source_workflow: errorData.source_workflow,
    delay_applied_ms: delayMs
  }
};

